78	+/// The theory-version **state backend**: the single owner of the version set and
79	+/// the monotonic version counter. [`Server`] holds no version map of its own and
80	+/// drives all version state exclusively through this trait, so a consumer can
81	+/// supply an asynchronous, internally-caching backend that remains the sole owner
82	+/// of theory state ([`InMemoryState`] is the reference in-memory implementation).
83	+///
84	+/// The lifecycle semantics below are the **contract** a backend must satisfy for
85	+/// the observed web-UI behaviour to hold (probed live; `BEHAVIOR.md` §§13.1/14.3,
86	+/// §16). One global index namespace covers every loaded, uploaded, or
87	+/// proof-derived version:
88	+///
89	+/// * **Monotonic allocation.** [`insert_new`](StateOps::insert_new) stores the
90	+///   theory at `= (max index ever allocated) + 1`, never reusing an index and
91	+///   independent of any base index. The first allocation on a fresh backend is
92	+///   index `1` (the originally loaded theory).
93	+/// * **Retention.** Every allocated index stays resolvable by
94	+///   [`get`](StateOps::get) for the backend's lifetime; the web layer never asks
95	+///   for a version to be dropped (the index-page window is a display cap only).
96	+/// * **In-place mutation.** [`replace`](StateOps::replace) overwrites the theory
97	+///   at an existing index (structural edits + `reload`) without allocating, and
98	+///   leaves the counter and every other version untouched. The web layer only
99	+///   calls it on an index it has already resolved.
100	+/// * **Enumeration.** [`entries`](StateOps::entries) yields all `(index, theory)`
101	+///   in ascending index order (drives the index page).
102	+/// * **Deletion.** [`remove`](StateOps::remove) drops a version. Under the observed
103	+///   retention contract the web layer never invokes it; it is part of the
104	+///   backend's ownership surface (e.g. cache eviction) — see the honesty note in
105	+///   `REPORT.md`.
106	+pub trait StateOps {
107	+    /// The per-version theory handle, shared with [`ProverOps::Theory`].
108	+    type Theory;
109	+    /// Allocate a fresh monotonic index, store `theory` there, and return the
110	+    /// index (never reused; `1` on a fresh backend). Prior versions are retained.
111	+    fn insert_new(&mut self, theory: Self::Theory) -> u64;
112	+    /// Retrieve the theory at `index`, or `None` if no such version exists.
113	+    fn get(&self, index: u64) -> Option<&Self::Theory>;
114	+    /// Overwrite the theory at an existing `index` in place (no allocation; the
115	+    /// counter and other versions are untouched).
116	+    fn replace(&mut self, index: u64, theory: Self::Theory);
117	+    /// Remove the version at `index` (returning it if present). Not exercised by
118	+    /// the current web-layer surface — see the trait-level note.
119	+    fn remove(&mut self, index: u64) -> Option<Self::Theory>;
120	+    /// All `(index, theory)` pairs in ascending index order.
121	+    fn entries(&self) -> Vec<(u64, &Self::Theory)>;
122	+}
